+    #[test]
+    fn step_availability_unclassified_command_is_unknown() {
+        let step = CompiledStep {
+            ordinal: 1, phase: "?".to_owned(), purpose: "?".to_owned(),
+            command: "nonexistent-future-command".to_owned(),
