+    #[test]
+    fn step_availability_passthrough_command_is_unknown() {
+        let step = CompiledStep {
+            ordinal: 1, phase: "local".to_owned(), purpose: "Help".to_owned(),
+            command: "help".to_owned(),
+            command_line: "fwc help".to_owned(),
